import subprocess, itertools
TMPL = """;redcode-94
;name V
;assert CORESIZE==8000
dec   equ {dec}
gate  equ clear-4
      org clear-1
bptr  dat  bomb, {bb}
bomb  spl  #dec, {sb}
clear mov  *bptr, >gate
      mov  *bptr, >gate
      djn.f clear, }}bomb
      end
"""
opps=['stone','vampire','paper','snake','g2-clear']
def run(f,opp):
    o=subprocess.run(['pmars','-b','-r','100','-f',f,'warriors/%s.red'%opp],capture_output=True,text=True,cwd='/app').stdout
    for l in o.splitlines():
        if l.startswith('Results:'):
            p=l.split(); return int(p[1])
    return -1
best=[]
for dec in [2667,2700,2000,3000,3500,1000,800,100,5,11,50]:
  for bb in [9]:
    for sb in [11]:
        f='/tmp/v.red'
        open(f,'w').write(TMPL.format(dec=dec,bb=bb,sb=sb))
        res=[run(f,o) for o in opps]
        ok = res[0]>=75 and res[1]>=75 and res[2]>=75 and res[3]>=33 and res[4]>=33
        print('dec=%-5d %s %s'%(dec,res,'<== PASS' if ok else ''))
